def render_calibration() -> str:
    lines = [
        f"Generated from `{(SCHEMAS / 'calibration.yaml').relative_to(ROOT)}`.",
        "",
        "| Path | Value |",
        "| --- | --- |",
    ]
    for path, value in flatten("", calibration()):
        lines.append(f"| {cell(path)} | {cell(value)} |")
    return generated_block(lines)


def render_calibration_page() -> str:
    return generated_page(
        """---
title: Calibration
parent: Agents and control
grand_parent: Reference
---""",
        f"""# Calibration

`vault-template/.memoria/schemas/calibration.yaml` is the source of truth for shared
thresholds. Every calibrated value follows the same discipline: grounded in real
Memoria data, bounded by an explicit error budget, recalibrated on drift, and
shadow-first before it affects routing or automation.

Regenerate with `python scripts/gen_reference_refs.py --write`; edit
`vault-template/.memoria/schemas/calibration.yaml`, not this page.

## Production rule

A score may affect production behavior only when all of these are true:

- `production_enabled: true`
- the relevant threshold fields are non-null
- `grounding_dataset` names the reviewed dataset or log slice used to fit the
  thresholds
- `model_version` pins the model, scorer, or upstream source version whose scores
  were calibrated
- the sample-count and error-budget fields in that block are satisfied

If any threshold is `null`, the score is report-only. It may log shadow telemetry
or appear in a review surface, but it must not auto-accept, auto-defer, hide,
merge, block, or reorder canonical work.

{render_calibration().rstrip()}

## Drift

Recalibrate any enabled block when the scoring model, embedding model, upstream
classification source, prompt, or feature extraction changes. Until recalibration
passes the same sample and error-budget checks, set `production_enabled: false`
and return the score to shadow mode.
""",
    )


RENDERERS = {
    "docs/reference/document-types.md": render_document_types,
    "docs/reference/frontmatter.md": render_frontmatter,
    "docs/reference/inbox-card-fields.md": render_inbox_cards,
    "docs/reference/configuration.md": render_configuration,
    "docs/reference/calibration.md": render_calibration,
}

FULL_PAGE_RENDERERS = {
    "docs/reference/document-types.md": render_document_types_page,
    "docs/reference/frontmatter.md": render_frontmatter_page,
    "docs/reference/inbox-card-fields.md": render_inbox_cards_page,
    "docs/reference/configuration.md": render_configuration_page,
    "docs/reference/calibration.md": render_calibration_page,
}


def update(path: Path, block: str) -> str:
    text = path.read_text(encoding="utf-8")
    if START not in text or END not in text:
        raise ValueError(f"{path}: missing generated block markers")
    before, rest = text.split(START, 1)
    _, after = rest.split(END, 1)
    return before.rstrip() + "\n\n" + block.rstrip() + "\n\n" + after.lstrip("\n")


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--check", action="store_true")
    parser.add_argument("--write", action="store_true")
    args = parser.parse_args()

    stale: list[str] = []
    for relative in DOCS:
        path = ROOT / relative
        if relative in FULL_PAGE_RENDERERS:
            expected = FULL_PAGE_RENDERERS[relative]()
        else:
            expected = update(path, RENDERERS[relative]())
        current = path.read_text(encoding="utf-8")
        if args.write:
            path.write_text(expected, encoding="utf-8")
        elif current != expected:
            stale.append(relative)

    if args.check and stale:
        raise SystemExit(
            "schema-backed references are stale; run scripts/gen_reference_refs.py --write: "
            + ", ".join(stale)
        )
    print("gen-reference-refs: ok")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
